		/// <summary>
		/// Debuja el tile chico.
		/// </summary>
		/// <param name="g">EL video</param>
		/// <param name="i"></param>
		/// <param name="j"></param>
		public void DibujarTileChico(Video g, int i, int j, bool semiTrasparente)
		{
			if (i < 0 || j < 0 || i >= m_anchoEnTilesMapaFisico || j >= m_altoEnTilesMapaFisico)
			{
				return;
			}

			int posicionInicioX = m_camara.InicioX + (((i - j) * m_tileAncho / 2) >> 1) + m_camara.X + m_tileAncho / 4;
			int posicionInicioY = m_camara.InicioY + (((i + j) * m_tileAlto / 2) >> 1) + m_camara.Y;

			if (semiTrasparente)
			{
				if (m_imagenTileGris == null)
				{
					m_imagenTileGris = AdministradorDeRecursos.Instancia.ObtenerImagen(Res.IMG_TILE_GRIS);
					m_imagenTileGris.SetearAlpha(125);
				}
				g.Dibujar(m_imagenTileGris, 0, 0, 32, 16, (short)(posicionInicioX), (short)(posicionInicioY));

			}
			else
			{
				Rectangle rect = m_tilesetDebug.ObtenerRectanguloDelTile(Res.TILE_DEBUG_ID_TILE_CHICO);
				g.Dibujar(m_tilesetDebug.Imagen, (short)rect.X, (short)rect.Y, (short)rect.Width, (short)rect.Height, (short)(posicionInicioX), (short)(posicionInicioY));
			}
		}


		/// <summary>
		/// Dibuja el último path calculado en el Pathfinder.
		/// </summary>
		/// <param name="g"></param>
		/// <param name="stack"></param>
		private void DibujarUltimoPathChico(Video g, Stack<Point> stack)
		{
			if (stack == null)
			{
				return;
			}

			foreach (Point p in stack)
			{
				DibujarTileChico(g, p.X, p.Y, false);
			}
		}



		/// <summary>
		/// Dibuja el layer dado.
		/// </summary>
		/// <param name="g"> El graphics donde la capa va a ser escrita</param>
		/// <param name="layer">El número de layer a dibujar. 0 es el background</param>
		public bool DibujarCapa(Video g, int layer)
		{
			if (layer > m_numeroMaximoDeCapas || layer < 0)
			{
				Log.Instancia.Error("No se peude pintar el layer dado porque no existe.");
				return false;
			}

			if (!m_mapaCargado)
			{
				Log.Instancia.Error("El mapa no esta cargado aún");
				return false;
			}

			Rectangle oldClip = g.ObtenerClip();

			g.SetearClip(m_camara.InicioX, m_camara.InicioY, m_camara.Ancho, m_camara.Alto);


			bool cambio = true;

			Tileset tileSet;


			Point p = CalcularPrimerTileAPintar(m_camara.X, m_camara.Y);

			int XX = p.X;
			int YY = p.Y;


			int posicionInicioX = m_camara.InicioX + (((XX - YY) * m_tileAncho) >> 1) + m_camara.X;
			int posicionInicioY = m_camara.InicioY + (((XX + YY) * m_tileAlto) >> 1) + m_camara.Y;

			cambio = true;
			int tileX = 0;

			while (posicionInicioY <= (m_camara.Alto + m_camara.InicioY))
			{

				for (int i = XX, j = YY; (tileX * (m_tileAncho) + posicionInicioX) <= (m_camara.InicioX + m_camara.Ancho) && j >= 0; i++, j--)
				{
					if (i < m_altoEnTiles && i >= 0 && j < m_anchoEnTiles && j >= 0)
					{
						int tileId = m_mapa[layer][i, j];

						// Si el tile no esta vacío
						if (tileId != 0)
						{
							tileSet = ObtenerTileset(tileId);
							tileId = tileId - tileSet.PrimerGid;
							Rectangle finalRet = tileSet.ObtenerRectanguloDelTile(tileId);

							g.Dibujar(tileSet.Imagen, finalRet.X, finalRet.Y, finalRet.Width, finalRet.Height, (tileX * (m_tileAncho) + posicionInicioX), posicionInicioY);

#if DEBUG && MOSTRAR_INFO_MAPA

							g.Escribir("" + i + ", " + j, (short)((tileX * (m_tileAncho) + posicionInicioX) + 20), (short)(posicionInicioY), 0);
#endif

						}
					}
					tileX++;

				}

				tileX = 0;
				posicionInicioY += m_tileAlto >> 1;

				if (cambio == true)
				{
					XX++;
					cambio = false;
					posicionInicioX += m_tileAncho >> 1;
				}
				else
				{
					cambio = true;
					posicionInicioX -= m_tileAncho >> 1;
					YY++;
				}

			}
			g.SetearClip(oldClip.X, oldClip.Y, oldClip.Width, oldClip.Height);
			return true;

		}


		/// <summary>
		/// Se fija en donde empieza la pantalla. En que tile hay que empezar a pintar.
		/// </summary>
		/// <returns>El punto i, j del primer tile a pintar en el mapa.</returns>
		private Point CalcularPrimerTileAPintar(int x, int y)
		{
			Point p = new Point();

			int a = -y / m_tileAlto;
			int b = x / m_tileAncho;

			if (x > 0)
			{
				b++;
			}
			p.X = a - b;
			p.Y = a + b;

			p.X -= 1;
			p.X--;
			p.Y--;
			return p;
		}

		/// <summary>
		/// Actaliza el m_mapa. Se fija si scrollearon, por ejemplo.
		/// </summary>
		public void Actualizar()
		{
			//int timeAn = Sdl.SDL_GetTicks();

			if (!m_mapaCargado)
			{
				Log.Instancia.Error("El mapa no esta cargado aun");
				return;
			}
			Point p;
			if (Mouse.Instancia.X < m_camara.Borde)
			{
				if (m_camara.X + m_camara.Velocidad <= (m_anchoEnTiles * m_tileAncho) / 2)
				{
					p = CalcularPrimerTileAPintar(m_camara.X, m_camara.Y);

					if (p.X < -13)
					{
						m_camara.Y -= m_camara.Velocidad / 2;
					}
					else
					{
						p = CalcularPrimerTileAPintar(m_camara.X, m_camara.Y - m_camara.Alto);

						if (p.Y > m_altoEnTiles + 13)
						{
							m_camara.Y += m_camara.Velocidad / 2;
						}
					}
					m_camara.X += m_camara.Velocidad;

				}
			}

			if (Mouse.Instancia.Y > m_camara.Alto - m_camara.Borde)
			{
				if ((m_camara.Y - m_camara.Velocidad)
					>= (m_camara.Alto - m_altoEnTiles * m_tileAlto) &&
					m_camara.Y - m_camara.Velocidad <= 0)
				{
					p = CalcularPrimerTileAPintar(m_camara.X, m_camara.Y - m_camara.Alto);

					if (p.Y > m_altoEnTiles + 13)
					{
						m_camara.Y -= m_camara.Velocidad / 2;
						m_camara.X -= m_camara.Velocidad;
					}
					else
					{
						p = CalcularPrimerTileAPintar(m_camara.X - m_camara.Ancho, m_camara.Y - m_camara.Alto);
						if (p.X > m_anchoEnTiles + 13)
						{
							m_camara.Y -= m_camara.Velocidad / 2;
							m_camara.X += m_camara.Velocidad;
						}
						else
						{
							m_camara.Y -= m_camara.Velocidad;
						}
					}
				}
			}

			if (Mouse.Instancia.Y < m_camara.Borde)
			{
				if (m_camara.Y + m_camara.Velocidad <= 0)
				{
					p = CalcularPrimerTileAPintar(m_camara.X, m_camara.Y);

					if (p.X < -13)
					{
						m_camara.X -= m_camara.Velocidad;
						m_camara.Y += m_camara.Velocidad / 2;
					}
					else
					{
						p = CalcularPrimerTileAPintar(m_camara.X - m_camara.Ancho, m_camara.Y);

						if (p.Y < -13)
						{
							m_camara.X += m_camara.Velocidad;
							m_camara.Y += m_camara.Velocidad / 2;
						}
						else
						{
							m_camara.Y += m_camara.Velocidad;
						}
					}
				}
			}

			if (Mouse.Instancia.X > m_camara.Ancho - m_camara.Borde)
			{
				p = CalcularPrimerTileAPintar(m_camara.X - m_camara.Ancho, m_camara.Y);

				if ((m_camara.X - m_camara.Ancho - m_camara.Velocidad + m_tileAncho)
					>= -(m_anchoEnTiles * m_tileAncho) / 2 ||
					(m_camara.X - m_camara.Velocidad) > 0)
				{
					if (p.Y < -13)
					{
						m_camara.Y -= m_camara.Velocidad / 2;
					}
					else
					{
						p = CalcularPrimerTileAPintar(m_camara.X - m_camara.Ancho, m_camara.Y - m_camara.Alto);
						if (p.X > m_altoEnTiles + 13)
						{
							m_camara.Y += m_camara.Velocidad / 2;
						}
					}
					m_camara.X -= m_camara.Velocidad;
				}
			}

			ActualizarCoordenadasDelMouse();
			//int timeDesp = Sdl.SDL_GetTicks();

			//Log.Instancia.Debug("Tiempo actualizarMapa = " + (timeDesp - timeAn));
		}

		/// <summary>
		/// Se fija en qué tile esta apoyado el puntero del mouse.
		/// </summary>
		private void ActualizarCoordenadasDelMouse()
		{
			if (!m_mapaCargado)
			{
				Log.Instancia.Error("El mapa no esta cargado aun");
				return;
			}

			Point p = CalcularPosicionDelTileEnXY(Mouse.Instancia.X, Mouse.Instancia.Y);
			m_tileMouse.X = p.X;
			m_tileMouse.Y = p.Y;
		}

		/// <summary>
		/// Se fija a que tile del mapa pertenece la posición (x, y).
		/// </summary>
		/// <param name="x">El punto x a fijarse a donde pertenece.</param>
		/// <param name="y">El punto y a fijarse a donde pertenece.</param>
		/// <returns>El punto en i, j del tile al que pertenece el punto.</returns>
		private Point CalcularPosicionDelTileEnXY(int x, int y)
		{
			int a = 0;
			int b = 0;
			int restoX = 0;
			int restoY = 0;

			Point punto = new Point();


			a = ((y - m_camara.Y - m_camara.InicioY) / m_tileAlto);
			restoY = ((y - m_camara.Y - m_camara.InicioY) % m_tileAlto);

			if (x - m_camara.X > 0)
			{
				b = (x - m_camara.X - m_camara.InicioX) / m_tileAncho;
				restoX = (x - m_camara.X - m_camara.InicioX) % m_tileAncho;
			}
			else
			{
				b = (x - m_camara.X - m_camara.InicioX - m_tileAncho) / m_tileAncho;
				restoX = (x - m_camara.X - m_camara.InicioX - m_tileAncho) % m_tileAncho;
				restoX = -restoX;
			}

			punto.X = a + b;
			punto.Y = a - b;

			Rectangle rect = m_tilesetDebug.ObtenerRectanguloDelTile(Res.TILE_DEBUG_ID_TILES_VECINOS);
			restoY += m_tilesetDebug.AltoDelTile - m_tileAlto;

			int color = m_tilesetDebug.Imagen.ColorPixel(restoX, restoY);

			if (x - m_camara.X < 0)
			{
				if (color == Video.ConvertirColor(Definiciones.COLOR_ROJO))
				{
					punto.Y--;
				}
				if (color == Video.ConvertirColor(Definiciones.COLOR_VERDE))
				{
					punto.X--;
				}
				if (color == Video.ConvertirColor(Definiciones.COLOR_AZUL))
				{
					punto.X++;
				}
				if (color == Video.ConvertirColor(Definiciones.COLOR_CELESTE))
				{
					punto.Y++;
				}
			}
			else
			{
				if (color == Video.ConvertirColor(Definiciones.COLOR_ROJO))
				{
					punto.X--;
				}
				if (color == Video.ConvertirColor(Definiciones.COLOR_VERDE))
				{
					punto.Y--;
				}
				if (color == Video.ConvertirColor(Definiciones.COLOR_AZUL))
				{
					punto.Y++;
				}
				if (color == Video.ConvertirColor(Definiciones.COLOR_CELESTE))
				{
					punto.X++;
				}
			}

			m_tileChicoMouse.X = punto.X * 2;
			m_tileChicoMouse.Y = punto.Y * 2;

			rect = m_tilesetDebug.ObtenerRectanguloDelTile(Res.TILE_DEBUG_ID_TILE_CHICO_VECINOS);
			restoX += m_tileAncho * Res.TILE_DEBUG_ID_TILE_CHICO_VECINOS;

			color = m_tilesetDebug.Imagen.ColorPixel(restoX, restoY);

			if (x - m_camara.X < 0)
			{

				if (color == Video.ConvertirColor(Definiciones.COLOR_VERDE))
				{
					m_tileChicoMouse.Y++;
				}
				if (color == Video.ConvertirColor(Definiciones.COLOR_AZUL))
				{
					m_tileChicoMouse.X++;
				}
				if (color == Video.ConvertirColor(Definiciones.COLOR_CELESTE))
				{
					m_tileChicoMouse.X++;
					m_tileChicoMouse.Y++;
				}
			}
			else
			{
				if (color == Video.ConvertirColor(Definiciones.COLOR_VERDE))
				{
					m_tileChicoMouse.X++;
				}
				if (color == Video.ConvertirColor(Definiciones.COLOR_AZUL))
				{
					m_tileChicoMouse.Y++;
				}
				if (color == Video.ConvertirColor(Definiciones.COLOR_CELESTE))
				{
					m_tileChicoMouse.X++;
					m_tileChicoMouse.Y++;
				}

			}

			return punto; ;
		}

