		/// <summary>
		/// Se fija a qué tileset pertenece el tileId.
		/// </summary>
		/// <param name="tileId">El id del tile a pasar.</param>
		/// <returns>Devuelve aqui una referencia al tileset a la que pertenece el tile dado.</returns>
		public Tileset ObtenerTileset(int tileId)
		{
			int i = 0;
			Tileset tileset = null;
			while (i < m_tilesetMaximo)
			{
				if (tileId >= m_tilesets[i].PrimerGid)
				{
					tileset = m_tilesets[i];
				}
				i++;
			}
			return tileset;
		}

		/// <summary>
		/// Carga el m_mapa.
		/// </summary>
		/// <param name="mapId">El Id del m_mapa a cargar.</param>
		public bool Cargar(int mapId)
		{

			if (m_mapaCargado)
			{
				m_mapa = null;
			}

			m_tilesetMaximo = 0;
			m_numeroMaximoDeCapas = 0;

			if (AdministradorDeRecursos.Instancia.PathsEscenarios == null)
			{
				Log.Instancia.Error("No se puede cargar el mapa porque hubo algun error durante la carga de los paths");
				return false;
			}

			if (mapId < Res.TLS_COUNT || mapId >= (Res.TLS_COUNT + Res.MAP_COUNT))
			{
				Log.Instancia.Error("Map ID " + mapId + " inválido ");
				return false;
			}


			if (!LeerInfoMapa(mapId))
			{
				return false;
			}

			if (!LeerTilesets(mapId))
			{
				return false;
			}

			if (!LeerCapas(mapId))
			{
				return false;
			}

			//Empiezo a leer el m_mapa.

			CargarCapaInfo();

			m_mapaCargado = true;
			return true;
		}


		/// <summary>
		/// Lee las capas de mapa mapId
		/// </summary>
		/// <param name="mapId">El id del mapa a cargar</param>
		/// <returns>true si pudo leer las capas correctamente.</returns>
		private bool LeerCapas(int mapId)
		{
			XmlTextReader lector = new XmlTextReader(AdministradorDeRecursos.Instancia.PathsEscenarios[mapId]);
			string encoding;
			m_nombresCapas = new Hashtable();

			try
			{
				while (lector.Read())
				{
					if (lector.NodeType == XmlNodeType.Element && lector.Name == "layer")
					{
						lector.MoveToAttribute("name");

						if (lector.Name == "name")
						{
							m_nombresCapas.Add(lector.Value, m_numeroMaximoDeCapas);
							switch (lector.Value.Trim().ToLower())
							{
								case "obstaculos":
									{
										CAPA_OBSTACULOS = m_numeroMaximoDeCapas;
									}
									break;

								case "terreno":
									{
										CAPA_TERRENO = m_numeroMaximoDeCapas;
									}
									break;

								case "unidades":
									{
										CAPA_UNIDADES_JUGADOR = m_numeroMaximoDeCapas;
									}
									break;

								case "posicion invalidada":
									{
										CAPA_POSICIONES_INVALIDADAS = m_numeroMaximoDeCapas;
									}
									break;
							}
						}

						encoding = "";

						// termino de leer el resto de la capa.
						while (lector.Read() && !(lector.NodeType == XmlNodeType.EndElement && lector.Name == "layer"))
						{
							if (lector.NodeType == XmlNodeType.Element)
							{
								if (lector.Name == "data")
								{
									lector.MoveToAttribute("encoding");
									if (lector.Name == "encoding")
									{
										encoding = lector.Value;
									}

									//Convierto la data en el mapa.
									string data = lector.ReadString();

									if (encoding == "base64")
									{
										if (m_mapa == null)
										{
											//Creo el m_mapa con la cantidad máxima de capas + 1 
											//para la capa de informacion j debug.
											m_mapa = new short[NRO_MAXIMO_DE_CAPAS + 1][,];
										}

										data = data.Trim();
										byte[] decbuff = Convert.FromBase64String(data);

										if (m_numeroMaximoDeCapas == NRO_MAXIMO_DE_CAPAS)
										{
											lector.Close();
											return false;
										}
										int index = 0;
										m_mapa[m_numeroMaximoDeCapas] = new short[m_altoEnTiles, m_anchoEnTiles];
										for (int i = 0; i < m_altoEnTiles; i++)
										{
											for (int j = 0; j < m_anchoEnTiles; j++)
											{
												m_mapa[m_numeroMaximoDeCapas][j, i] = decbuff[index];
												index += 4;
											}
										}
										m_numeroMaximoDeCapas++;
									}
								}
							}
						} //termino de leer el layer
					}
				}

				lector.Close();
				lector = null;
			}
			catch (Exception e)
			{
				Log.Instancia.Error("Error al leer el archivo xml " + AdministradorDeRecursos.Instancia.PathsEscenarios[mapId] + ". " + e.Message);
				lector.Close();
				lector = null;
				return false;
			}
			return true;
		}

		/// <summary>
		/// Lee los tilesets que estan dentro del mapa apId.
		/// </summary>
		/// <param name="mapId">el id del mapa a leer</param>
		/// <returns>true si pudo leer los tilesets correctamente.</returns>
		private bool LeerTilesets(int mapId)
		{
			XmlTextReader lector = new XmlTextReader(AdministradorDeRecursos.Instancia.PathsEscenarios[mapId]);

			try
			{

				while (lector.Read())
				{
					if (lector.NodeType == XmlNodeType.Element && lector.Name == "tileset")
					{

						Tileset tileSet = new Tileset();

						while (lector.MoveToNextAttribute())
						{

							if (lector.Name == "firstgid")
							{
								tileSet.PrimerGid = Convert.ToInt16(lector.Value);
							}

							if (lector.Name == "source")
							{
								string path = Utilidades.ObtenerPath(Path.Combine(Programa.PATH_ESCENARIOS, lector.Value));
								if (path == null)
								{
									return false;
								}

								tileSet.Cargar(path);
							}
						}
						m_tilesets[m_tilesetMaximo++] = tileSet;
					}
				}
			}
			catch (Exception e)
			{
				Log.Instancia.Error("No se pudieron cargar los tilesets." + e);
				lector.Close();
				lector = null;
				return false;
			}

			lector.Close();
			lector = null;
			return true;

		}

		/// <summary>
		/// Lee la información del mapa: las dimensiones del mapa.
		/// </summary>
		/// <param name="mapId">El id del mapa a leer.</param>
		/// <returns>true si pudo cargar bien el mapa.</returns>
		private bool LeerInfoMapa(int mapId)
		{

			int tileCamaraI = 0;
			int tileCamaraJ = 0;

			XmlTextReader lector = new XmlTextReader(AdministradorDeRecursos.Instancia.PathsEscenarios[mapId]);
			try
			{

				while (lector.Read())
				{
					if (lector.NodeType == XmlNodeType.Element && lector.Name == "map")
					{
						lector.MoveToAttribute("orientation");

						if (lector.Name == "orientation")
						{
							if (lector.Value != "isometric")
							{
								return false;
							}
						}

						//Leo el ancho del mapa.
						lector.MoveToAttribute("width");
						if (lector.Name == "width")
						{
							m_anchoEnTiles = Convert.ToInt16(lector.Value);
							m_anchoEnTilesMapaFisico = m_anchoEnTiles * 2;

						}
						else
						{
							Log.Instancia.Error("No se puede leer el ancho del mapa.");
							return false;
						}

						//Leo el alto del mapa
						lector.MoveToAttribute("height");
						if (lector.Name == "height")
						{
							m_altoEnTiles = Convert.ToInt16(lector.Value);
							m_altoEnTilesMapaFisico = m_altoEnTiles * 2;
						}
						else
						{
							Log.Instancia.Error("No se puede leer el alto del mapa.");
							return false;
						}

						//Leo el ancho del tile
						lector.MoveToAttribute("tilewidth");
						if (lector.Name == "tilewidth")
						{
							m_tileAncho = Convert.ToInt16(lector.Value);
							m_tileFisicoAncho = m_tileAncho / 2;
						}
						else
						{
							Log.Instancia.Error("No se puede leer el ancho del tile.");
							return false;
						}

						//Leo el alto del tile.
						lector.MoveToAttribute("tileheight");
						if (lector.Name == "tileheight")
						{
							m_tileAlto = Convert.ToInt16(lector.Value);
							m_tileFisicoAlto = m_tileAlto / 2;
						}
						else
						{
							Log.Instancia.Error("No se puede leer el alto del tile.");
							return false;
						}

					}

					//leo el elemento properties, es una lista con propiedades especificas del mapa:
					if (lector.NodeType == XmlNodeType.Element && lector.Name == "properties")
					{

						while (lector.Read() && !(lector.NodeType == XmlNodeType.EndElement && lector.Name == "properties"))
						{
							if (lector.NodeType == XmlNodeType.Element)
							{
								if (lector.Name == "property")
								{
									lector.MoveToAttribute("name");
									if (lector.Name == "name")
									{
										switch (lector.Value)
										{
											case "CamaraTileInicialJ":
												lector.MoveToAttribute("value");
												if (lector.Name == "value")
												{
													tileCamaraJ = Convert.ToInt16(lector.Value);
												}
												break;
											case "CamaraTileInicialI":
												lector.MoveToAttribute("value");

												if (lector.Name == "value")
												{
													tileCamaraI = Convert.ToInt16(lector.Value);
												}
												break;
										}
									}
								}
							}
						}
					}
				}
				m_camara.X = ((tileCamaraJ - tileCamaraI) * m_tileAncho) >> 1;
				m_camara.Y = -((tileCamaraJ + tileCamaraI) * m_tileAlto) >> 1;

			}
			catch (Exception e)
			{
				Log.Instancia.Error("No se puede leer el mapa. " + e);
				lector.Close();
				return false;
			}

			lector.Close();
			lector = null;
			return true;
		}

		/// <summary>
		/// Carga la capa que contine la información sobre que tiles puede ser 
		/// caminables y cuales no.
		/// Utilizada por la clase PathFinding
		/// </summary>
		private void CargarCapaInfo()
		{
			if (m_tilesetDebug == null)
			{
				m_tilesetDebug = new Tileset();
			}

			m_tilesetDebug.Cargar(AdministradorDeRecursos.Instancia.PathsEscenarios[Res.TLS_DEBUG]);
			m_mapa[CAPA_INFO] = new short[m_altoEnTiles, m_anchoEnTiles];

			Tileset tileset;

			m_mapaTilesFisicos = new short[m_altoEnTiles * 2, m_anchoEnTiles * 2];

			for (int capa = 0; capa < m_numeroMaximoDeCapas; capa++)
			{
				for (int i = 0; i < m_anchoEnTiles; i++)
				{
					for (int j = 0; j < m_altoEnTiles; j++)
					{
						//Cargo la informacion de los tiles en cada mapa
						//BUG FIX: Se invalidan los tiles de los edificios igualmente porque sino se puede llegar a borrar
						//el edificio.
						tileset = ObtenerTileset(m_mapa[capa][i, j]);
						if (tileset != null && tileset.Id != Res.TLS_UNIDADES /*&& tileset.Id != Res.TLS_EDIFICIOS && tileset.Id != Res.TLS_ENFERMERIA*/)
						{
							m_mapa[CAPA_INFO][i, j] = tileset.Id;
							m_mapaTilesFisicos[i * 2, j * 2] = tileset.Id;
							m_mapaTilesFisicos[i * 2, j * 2 + 1] = tileset.Id;
							m_mapaTilesFisicos[i * 2 + 1, j * 2] = tileset.Id;
							m_mapaTilesFisicos[i * 2 + 1, j * 2 + 1] = tileset.Id;

						}
					}
				}
			}
			PathFinder.Instancia.CargarMapa(this);
		}


