		/// <summary>
		/// Se fija si la posicion x, y es caminable.
		/// </summary>
		public bool EsPosicionCaminable(int x, int y)
		{
			if (x < 0 || y < 0 || x >= (m_anchoEnTiles << 1) || y >= (m_altoEnTiles << 1))
			{
				return false;
			}

			return m_mapaTilesFisicos[x, y] == Res.TLS_PASTO || m_mapaTilesFisicos[x, y] == Res.TLS_TIERRA;
		}


        /// <summary>
        /// Se fija si la posicion x, y es caminable.
        /// </summary>
        public void InvalidarTile(int x, int y)
        {
            if (x < 0 || y < 0 || x + 1>= (m_anchoEnTiles << 1) || y + 1 >= (m_altoEnTiles << 1))
            {
                return ;
            }

            m_mapaTilesFisicos[x, y] = Res.TLS_ARBOLES;


            m_mapaTilesFisicos[x+1, y] = Res.TLS_ARBOLES;
            m_mapaTilesFisicos[x+1, y+1] = Res.TLS_ARBOLES;
            m_mapaTilesFisicos[x, y+1] = Res.TLS_ARBOLES;
        }




		public Point ObtenerPosicionEnLineaDeVision(int x1, int x2, int y1, int y2)
		{
			float columna = x1;
			float fila = y1;

			float decliveFila = ObtenerDecliveFila(x1, x2, y1, y2);
			float decliveColumna = ObtenerDecliveColumna(x1, x2, y1, y2);
			Log.Instancia.Debug("pos2: {" + x2 + ", " + y2 + "}, pos1: {" + x1 + ", " + y1 + "}");

			// Voy desde (x1, y1) a (x2, y2)
			if (Math.Abs(decliveFila) == 1)
			{
				while ((int)(Math.Floor(fila)) != y2)
				{
					if (EsPosicionCaminable((int)(Math.Floor(columna)), (int)(Math.Floor(fila))))
					{
						return new Point((int)(Math.Floor(columna)), (int)(Math.Floor(fila)));
					}
					// Incremento la fila y la columna
					fila += decliveFila;
					columna += decliveColumna;
					Log.Instancia.Debug("c: f:" + columna + ", " + fila);
				}
			}
			else
			{
				while ((int)(Math.Floor(columna)) != x2)
				{
					if (EsPosicionCaminable((int)(Math.Floor(columna)), (int)(Math.Floor(fila))))
					{
						return new Point((int)(Math.Floor(columna)), (int)(Math.Floor(fila)));
					}

					// Incremento la fila y la columna
					fila += decliveFila;
					columna += decliveColumna;
					Log.Instancia.Debug("c: f:" + columna + ", " + fila);
				}
			}
			return new Point(-1, -1);
		}

		private float ObtenerDecliveFila(int x1, int x2, int y1, int y2)
		{
			if (Math.Abs(y2 - y1) > Math.Abs(x2 - x1))
			{
				return y2 > y1 ? 1 : -1;
			}
			else
			{
				float declive = (float)(Math.Abs(y2 - y1)) / (float)(Math.Abs(x2 - x1));
				declive *= y2 > y1 ? 1 : -1;
				return declive;
			}
		}

		private float ObtenerDecliveColumna(int x1, int x2, int y1, int y2)
		{
			if (Math.Abs((float)x2 - x1) > ((float)y2 - y1))
				return (x2 > x1 ? 1 : -1);
			else
			{
				float declive = Math.Abs((float)(x2 - x1) / (float)(y2 - y1));
				declive *= (x2 > x1 ? 1 : -1);
				return declive;
			}

		}
